using System;
using System.Threading;

namespace Skillock.Application.Interfaces;

public interface IReportsService
{
    /// <summary>
    /// Genera un PDF con el reporte de todas las apuestas completadas y devuelve el contenido en bytes.
    /// </summary>
    Task<byte[]> GenerateCompletedBetsReportAsync(CancellationToken cancellationToken = default);
}

using Microsoft.EntityFrameworkCore;
using Skillock.Domain.Common;
using Skillock.Domain.Models;

namespace Skillock.Infrastructure.Persistence;

public class SkillockDbContext(DbContextOptions<SkillockDbContext> options) : DbContext(options)
{
    public DbSet<User> Users => Set<User>();
    public DbSet<Bet> Bets => Set<Bet>();
    public DbSet<BetParty> BetParties => Set<BetParty>();
    public DbSet<PartyMember> PartyMembers => Set<PartyMember>();
    public DbSet<Wallet> Wallets => Set<Wallet>();
    public DbSet<WalletTransaction> WalletTransactions => Set<WalletTransaction>();
    public DbSet<GameAccount> GameAccounts => Set<GameAccount>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        modelBuilder.ApplyConfiguration(new Configurations.UserConfiguration());
        modelBuilder.ApplyConfiguration(new Configurations.GameAccountConfiguration());
        modelBuilder.ApplyConfiguration(new Configurations.WalletConfiguration());
        modelBuilder.ApplyConfiguration(new Configurations.BetConfiguration());
        modelBuilder.ApplyConfiguration(new Configurations.BetPartyConfiguration());
        modelBuilder.ApplyConfiguration(new Configurations.PartyMemberConfiguration());
        modelBuilder.ApplyConfiguration(new Configurations.WalletTransactionConfiguration());
    }

    public override Task<int> SaveChangesAsync(CancellationToken cancellationToken = default)
    {
        var entries = ChangeTracker.Entries<BaseEntity>()
            .Where(e => e.State == EntityState.Modified);

        foreach (var entry in entries)
            entry.Entity.UpdatedAt = DateTime.UtcNow;

        return base.SaveChangesAsync(cancellationToken);
    }
}
